patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..108116c97aff 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1266,6 +1266,78 @@ Value *InstCombinerImpl::foldEqOfParts(Value *Cmp0, Value *Cmp1, bool IsAnd) {
   return Builder.CreateICmp(Pred, LValue, RValue);
 }

+/// Fold (icmp ult X, C) & (icmp eq (and X, Mask), Val) to (icmp eq (and X, Mask), Val)
+/// when all values satisfying the masked equality are less than C.
+/// For example: (x ult 5) & ((x & -2) eq 2) -> (x & -2) eq 2
+/// Because if (x & -2) == 2, then x is either 2 or 3, both of which are < 5.
+static Value *foldAndOfRangeCheckAndMaskedEq(ICmpInst *RangeCmp, ICmpInst *MaskedEq,
+                                             bool IsAnd, InstCombiner::BuilderTy &Builder) {
+  // For "and", we check if RangeCmp implies it can be dropped.
+  // For "or", we would need the opposite implication.
+  if (IsAnd) {
+    // Check if RangeCmp is a range check: X ult/ule/slt/sle C
+    ICmpInst::Predicate RPred = RangeCmp->getPredicate();
+    Value *RangeOp0 = RangeCmp->getOperand(0);
+    Value *RangeOp1 = RangeCmp->getOperand(1);
+    const APInt *RangeC;
+    if (!match(RangeOp1, m_APInt(RangeC)))
+      return nullptr;
+    bool IsUpperBound = (RPred == ICmpInst::ICMP_ULT || RPred == ICmpInst::ICMP_ULE ||
+                         RPred == ICmpInst::ICMP_SLT || RPred == ICmpInst::ICMP_SLE);
+    if (!IsUpperBound)
+      return nullptr;
+    
+    // Check if MaskedEq is: (and X, Mask) eq Val
+    Value *MaskedOp0 = MaskedEq->getOperand(0);
+    Value *MaskedOp1 = MaskedEq->getOperand(1);
+    const APInt *Val;
+    if (MaskedEq->getPredicate() != ICmpInst::ICMP_EQ || !match(MaskedOp1, m_APInt(Val)))
+      return nullptr;
+    
+    Value *AndOp0, *AndOp1;
+    const APInt *Mask;
+    if (!match(MaskedOp0, m_c_And(m_Value(AndOp0), m_APInt(Mask))))
+      return nullptr;
+    
+    // Check that RangeOp0 matches AndOp0 (possibly through trunc/zext)
+    if (RangeOp0 != AndOp0)
+      return nullptr;
+    
+    // Mask should be a negated power of 2 (like -2 = ~1, -4 = ~3, etc.)
+    // This means Mask has the form all_ones ^ (2^k - 1) for some k
+    APInt NegatedMask = ~*Mask;
+    if (!NegatedMask.isMask())  // Check if ~Mask is a mask (contiguous low bits set)
+      return nullptr;
+    
+    // Check that Val has all bits of ~Mask cleared
+    // i.e., Val & ~Mask == 0
+    if ((*Val & NegatedMask) != 0)
+      return nullptr;
+    
+    // The maximum value that satisfies (X & Mask) == Val is Val | ~Mask
+    APInt MaxVal = *Val | NegatedMask;
+    
+    // Check if MaxVal satisfies the range check
+    bool Satisfies;
+    if (RPred == ICmpInst::ICMP_ULT)
+      Satisfies = MaxVal.ult(*RangeC);
+    else if (RPred == ICmpInst::ICMP_ULE)
+      Satisfies = MaxVal.ule(*RangeC);
+    else if (RPred == ICmpInst::ICMP_SLT)
+      Satisfies = MaxVal.slt(*RangeC);
+    else if (RPred == ICmpInst::ICMP_SLE)
+      Satisfies = MaxVal.sle(*RangeC);
+    else
+      return nullptr;
+    
+    if (Satisfies) {
+      // Range check is implied by masked equality, so return MaskedEq
+      return MaskedEq;
+    }
+  }
+  return nullptr;
+}
+
 /// Reduce logic-of-compares with equality to a constant by substituting a
 /// common operand with the constant. Callers are expected to call this with
 /// Cmp0/Cmp1 switched to handle logic op commutativity.
@@ -3579,6 +3651,14 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
     return Builder.createIsFPClass(X, IsAnd ? FPClassTest::fcNormal
                                             : ~FPClassTest::fcNormal);

+  // Check if range check is implied by masked equality
+  if (IsAnd) {
+    if (Value *V = foldAndOfRangeCheckAndMaskedEq(LHS, RHS, IsAnd, Builder))
+      return V;
+    if (Value *V = foldAndOfRangeCheckAndMaskedEq(RHS, LHS, IsAnd, Builder))
+      return V;
+  }
+
   return foldAndOrOfICmpsUsingRanges(LHS, RHS, IsAnd);
 }

log.expect_optimized_program:
define i1 @merge_range_check_and(i8 %a) {
  %and = icmp eq i8 %a, 2
  ret i1 %and
}

