  %1 = and i32 %x, -32
  %2 = icmp eq i32 %1, 128
  ret i1 %2
}

define i1 @implied_range_check(i8 %a) {
  %1 = and i8 %a, -2
  %and = icmp eq i8 %1, 2
  ret i1 %and
}

